19	export function quote(_customer: Customer, items: Item[]): number {
20	  let total = 0;
21	  for (const item of items) {
22	    const base = BASE_PRICES[item.type] ?? 0;
23	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
24	  }
25	  total += PROCESSING_FEE;
26	  return Math.ceil(total);
27	}
